import yaml

# Custom representer to handle multi-line strings and preserve formatting
def str_representer(dumper, data):
    if '\n' in data:
        return dumper.represent_scalar('tag:yaml.org,2002:str', data, style='|')
    return dumper.represent_scalar('tag:yaml.org,2002:str', data)

yaml.add_representer(str, str_representer)

with open('/etc/monitoring/alerts.yaml', 'r') as f:
    data = yaml.safe_load(f)

# Find and modify rules
for group in data['groups']:
    if group['name'] == 'service_alerts':
        for rule in group['rules']:
            if rule['alert'] == 'HighLatency':
                rule['for'] = '3m'
            elif rule['alert'] == 'ServiceDown':
                rule['labels']['escalation_level'] = 'critical'

        # Add new DiskSpaceLow alert
        new_alert = {
            'alert': 'DiskSpaceLow',
            'expr': 'node_filesystem_avail_bytes{mountpoint="/"} / node_filesystem_size_bytes{mountpoint="/"} < 0.1',
            'for': '10m',
            'labels': {
                'severity': 'warning',
                'team': 'infrastructure'
            },
            'annotations': {
                'summary': 'Disk space below 10% on {{ $labels.instance }}'
            }
        }
        group['rules'].append(new_alert)

# Write back with comment preserved manually
with open('/etc/monitoring/alerts.yaml', 'w') as f:
    f.write('# Prometheus alerting rules\n')
    yaml.dump(data, f, default_flow_style=False, sort_keys=False, allow_unicode=True)

print('YAML updated successfully')
EOF
